import '../../protocol/navivox_json.dart';
import 'navivox_channel.dart';
import 'navivox_profile_scope.dart';

/// Gateway/test-facing decoder for the profile contact payload used by channel
/// state. Keeping it beside the channel contract avoids each channel adapter
/// re-implementing the same fallback policy.
NavivoxProfileContact navivoxProfileContactFromJson(Map<String, Object?> json) {
  final serverId = navivoxStringFromJson(
    json['server_id'],
    fallback: navivoxDefaultGatewayServerId,
  );
  final profileId = navivoxStringFromJson(
    json['profile_id'],
    fallback: navivoxDefaultProfileId,
  );
  final serverLabel = navivoxStringFromJson(
    json['server_label'],
    fallback: navivoxDefaultGatewayServerLabel,
  );
  final micAvailable = navivoxStrictBoolFromJson(json['mic_available']);
  return NavivoxProfileContact(
    serverId: serverId,
    profileId: profileId,
    displayName: navivoxStringFromJson(
      json['display_name'],
      fallback: profileId == navivoxDefaultProfileId
          ? 'Default profile'
          : profileId,
    ),
    serverLabel: serverLabel,
    health: navivoxProfileHealthFromJson(json['health']),
    latestPreview: navivoxStringFromJson(
      json['latest_preview'],
      fallback: 'Profile ready',
    ),
    latestPreviewKind: navivoxStringFromJson(
      json['latest_preview_kind'],
      fallback: 'status',
    ),
    latestAt: navivoxDateTimeFromJson(json['latest_preview_at']),
    workspaceRootCount: navivoxIntFromJson(json['workspace_root_count']),
    workspaceRootsOk: navivoxStrictBoolFromJson(
      json['workspace_roots_ok'],
      fallback: true,
    ),
    workspaceRootsWarning: navivoxIntFromJson(json['workspace_roots_warning']),
    workspaceRootsError: navivoxIntFromJson(json['workspace_roots_error']),
    attentionBadges: navivoxStringListFromJson(json['attention_badges']),
    micAvailable: micAvailable,
    voiceCapability: navivoxVoiceCapabilityFromJson(
      json['voice_capability'],
      micAvailable: micAvailable,
    ),
    activeTurnState: navivoxStringFromJson(
      json['active_turn_state'],
      fallback: 'idle',
    ),
    avatarSeed: navivoxStringFromJson(
      json['avatar_seed'],
      fallback: '$serverId:$profileId',
    ),
  );
}

NavivoxVoiceCapability navivoxVoiceCapabilityFromJson(
  Object? value, {
  required bool micAvailable,
}) {
  if (value is Map) {
    return NavivoxVoiceCapability(
      deviceStt: navivoxStringFromJson(
        value['device_stt'],
        fallback: micAvailable ? 'available' : 'unavailable',
      ),
      serverStt: navivoxStringFromJson(
        value['server_stt'],
        fallback: 'unavailable',
      ),
      serverTts: navivoxStringFromJson(
        value['server_tts'],
        fallback: 'unavailable',
      ),
      disabledReason: navivoxStringFromJson(
        value['disabled_reason'],
        fallback: micAvailable ? '' : 'mic unavailable',
      ),
      recoveryAction: navivoxStringFromJson(
        value['recovery_action'],
        fallback: '',
      ),
      isReported: true,
    );
  }
  return NavivoxVoiceCapability(
    deviceStt: micAvailable ? 'available' : 'unavailable',
    disabledReason: micAvailable ? '' : 'mic unavailable',
  );
}

import 'navivox_channel.dart';

/// Shared default profile/server scope for gateway-backed channel state.
///
/// Keeping these identity defaults together prevents profile decoders, memory
/// requests, voice runs, and fallback contacts from drifting when a gateway does
/// not provide explicit scope metadata.
const navivoxDefaultGatewayServerId = 'navivox-gateway';
const navivoxDefaultProfileId = 'default';
const navivoxDefaultGatewayServerLabel = 'Gormes Gateway';

/// Resolved server/profile identity used by gateway-backed channel contracts.
///
/// Memory requests may intentionally omit a server when no active profile or
/// explicit server was supplied, while voice-run records fall back to the
/// default gateway server. The optional server fallback keeps both policies on
/// the same profile-id fallback without forcing one server behavior on the
/// other.
class NavivoxProfileScope {
  const NavivoxProfileScope({this.serverId, required this.profileId});

  final String? serverId;
  final String profileId;
}

NavivoxProfileScope navivoxProfileScopeFor({
  required NavivoxProfileContact? activeProfile,
  String? serverId,
  String? profileId,
  String? fallbackServerId,
}) {
  return NavivoxProfileScope(
    serverId: serverId ?? activeProfile?.serverId ?? fallbackServerId,
    profileId: profileId ?? activeProfile?.profileId ?? navivoxDefaultProfileId,
  );
}

import 'navivox_channel.dart';
import 'navivox_profile_scope.dart';

/// Profile/server scope used by memory API requests.
///
/// Memory requests share the profile scope value object with voice-run and
/// profile-contact defaults, while keeping a memory-specific name at this seam.
typedef NavivoxMemoryScope = NavivoxProfileScope;

NavivoxMemoryScope navivoxMemoryScopeFor({
  required NavivoxProfileContact? activeProfile,
  String? serverId,
  String? profileId,
}) {
  final scope = navivoxProfileScopeFor(
    activeProfile: activeProfile,
    serverId: serverId,
    profileId: profileId,
  );
  return NavivoxMemoryScope(
    serverId: scope.serverId,
    profileId: scope.profileId,
  );
}

/// Server/profile scope attached to channel messages and gateway events.
typedef NavivoxMessageScope = ({String? serverId, String? profileId});

const NavivoxMessageScope navivoxUnscopedMessage = (
  serverId: null,
  profileId: null,
);

NavivoxMessageScope navivoxMessageScope({
  required String? serverId,
  required String? profileId,
}) {
  return (serverId: serverId, profileId: profileId);
}

/// Uses an existing message scope when present, falling back to an event scope.
///
/// Gateway transcript updates often merge into a prior local message. Preserving
/// that prior scope keeps follow-up assistant/tool events attached to the same
/// profile even when later gateway events omit profile metadata.
NavivoxMessageScope navivoxMessageScopeWithFallback({
  required String? serverId,
  required String? profileId,
  required NavivoxMessageScope fallback,
}) {
  return navivoxMessageScope(
    serverId: serverId ?? fallback.serverId,
    profileId: profileId ?? fallback.profileId,
  );
}

