String? _routingChoice(List<String> allowed, String? selected) {
  final candidate = selected?.trim();
  if (candidate != null &&
      candidate.isNotEmpty &&
      allowed.contains(candidate)) {
    return candidate;
  }
  return allowed.firstOrNull;
}

